def main(arg1: str) -> dict:
    def custom_url_encode(text):
        safe_chars = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789-_.~"
        encoded = []
        for char in text:
            if char in safe_chars:
                encoded.append(char)
            else:
                # 对非安全字符进行百分号编码
                encoded.append(''.join(f'%{byte:02X}' for byte in char.encode('utf-8')))
        return ''.join(encoded)
    
    encoded_text = custom_url_encode(arg1)
    return {'result': encoded_text}

import json
from typing import Any, Dict

def main(get_next_batch_res: str) -> dict:
    try:
        obj: Dict[str, Any] = json.loads(get_next_batch_res.strip())
    except Exception:
        obj = {}

    val = obj.get("has_more_batches")
    if isinstance(val, bool):
        has_more_batches_str = "true" if val else "false"
    elif val is None:
        has_more_batches_str = ""
    else:
        has_more_batches_str = str(val)

    return {
        "batch_id": obj.get("batch_id"),
        "has_more_batches": has_more_batches_str
    }

